class MessagingModelTests(TestCase):
    """Test the Messaging model"""
    
    def setUp(self):
        self.user1 = DjangoUser.objects.create_user(
            username='user1@test.com',
            email='user1@test.com',
            password='testpass123'
        )
        self.user2 = DjangoUser.objects.create_user(
            username='user2@test.com',
            email='user2@test.com',
            password='testpass123'
        )
    
    def test_create_message(self):
        """Test creating a message between two users"""
        message = Messaging.objects.create(
            author=self.user1,
            recipient=self.user2,
            content="Hello, this is a test message"
        )
        self.assertEqual(message.author, self.user1)
        self.assertEqual(message.recipient, self.user2)
        self.assertEqual(message.content, "Hello, this is a test message")
        self.assertIsNotNone(message.created_at)
    
    def test_message_ordering(self):
        """Test that messages are ordered by created_at"""
        msg1 = Messaging.objects.create(
            author=self.user1,
            recipient=self.user2,
            content="First message"
        )
        msg2 = Messaging.objects.create(
            author=self.user2,
            recipient=self.user1,
            content="Second message"
        )
        messages = Messaging.objects.all().order_by("created_at")
        self.assertEqual(messages[0], msg1)
        self.assertEqual(messages[1], msg2)


class NotificationModelTests(TestCase):
    """Test the Notification model"""
    
    def setUp(self):
        self.user1 = DjangoUser.objects.create_user(
            username='user1@test.com',
            email='user1@test.com',
            password='testpass123'
        )
        self.user2 = DjangoUser.objects.create_user(
            username='user2@test.com',
            email='user2@test.com',
            password='testpass123'
        )
        self.message = Messaging.objects.create(
            author=self.user1,
            recipient=self.user2,
            content="Test message"
        )
    
    def test_create_notification(self):
        """Test creating a notification"""
        notification = Notification.objects.create(
            recipient=self.user2,
            message=self.message
        )
        self.assertEqual(notification.recipient, self.user2)
        self.assertEqual(notification.message, self.message)
        self.assertFalse(notification.is_read)
        self.assertIsNotNone(notification.created_at)
    
    def test_mark_notification_as_read(self):
        """Test marking a notification as read"""
        notification = Notification.objects.create(
            recipient=self.user2,
            message=self.message
        )
        self.assertFalse(notification.is_read)
        
        notification.is_read = True
        notification.save()
        
        self.assertTrue(notification.is_read)
    
    def test_unread_notification_count(self):
        """Test counting unread notifications"""
        Notification.objects.create(recipient=self.user2, message=self.message)
        
        msg2 = Messaging.objects.create(
            author=self.user1,
            recipient=self.user2,
            content="Another message"
        )
        Notification.objects.create(recipient=self.user2, message=msg2)
        
        unread_count = Notification.objects.filter(
            recipient=self.user2,
            is_read=False
        ).count()
        
        self.assertEqual(unread_count, 2)


class GroupModelTests(TestCase):
    """Test the Group model"""
    
    def setUp(self):
        self.user1 = DjangoUser.objects.create_user(
            username='user1@test.com',
            email='user1@test.com',
            password='testpass123'
        )
        self.user2 = DjangoUser.objects.create_user(
            username='user2@test.com',
            email='user2@test.com',
            password='testpass123'
        )
        self.user3 = DjangoUser.objects.create_user(
            username='user3@test.com',
            email='user3@test.com',
            password='testpass123'
        )
    
    def test_create_group(self):
        """Test creating a group"""
        group = Group.objects.create(name="Test Group")
        group.members.add(self.user1, self.user2, self.user3)
        
        self.assertEqual(group.name, "Test Group")
        self.assertEqual(group.members.count(), 3)
        self.assertIn(self.user1, group.members.all())
    
    def test_group_message(self):
        """Test creating a message in a group"""
        group = Group.objects.create(name="Test Group")
        group.members.add(self.user1, self.user2)
        
        group_message = GroupMessage.objects.create(
            group=group,
            author=self.user1,
            content="Hello group!"
        )
        
        self.assertEqual(group_message.group, group)
        self.assertEqual(group_message.author, self.user1)
        self.assertEqual(group_message.content, "Hello group!")
        self.assertIsNotNone(group_message.timestamp)


