class SendMessageTests(TestCase):
    """Test sending messages"""
    
    def setUp(self):
        self.client = Client()
        self.user1 = DjangoUser.objects.create_user(
            username='user1@test.com',
            email='user1@test.com',
            password='testpass123'
        )
        self.user2 = DjangoUser.objects.create_user(
            username='user2@test.com',
            email='user2@test.com',
            password='testpass123'
        )
    
    def test_send_message_requires_login(self):
        """Test that sending a message requires login"""
        response = self.client.post(
            reverse('messaging:send-message', kwargs={'username': 'user2@test.com'}),
            {'content': 'Test'}
        )
        self.assertEqual(response.status_code, 302)
        self.assertIn('/login/', response.url)
    
    def test_send_message_creates_message(self):
        """Test that sending a message creates a Messaging object"""
        session = self.client.session
        session['user_data'] = {'email': 'user1@test.com', 'given_name': 'User1'}
        session.save()
        
        response = self.client.post(
            reverse('messaging:send-message', kwargs={'username': 'user2@test.com'}),
            {'content': 'Test message content'}
        )
        
        self.assertEqual(response.status_code, 302)  # Redirects after sending
        self.assertTrue(
            Messaging.objects.filter(
                author=self.user1,
                recipient=self.user2,
                content='Test message content'
            ).exists()
        )
    
    def test_send_message_creates_notification(self):
        """Test that sending a message creates a notification"""
        session = self.client.session
        session['user_data'] = {'email': 'user1@test.com', 'given_name': 'User1'}
        session.save()
        
        self.client.post(
            reverse('messaging:send-message', kwargs={'username': 'user2@test.com'}),
            {'content': 'Test notification'}
        )
        
        self.assertTrue(
            Notification.objects.filter(
                recipient=self.user2,
                is_read=False
            ).exists()
        )
    
    def test_send_empty_message_does_nothing(self):
        """Test that empty messages are not created"""
        session = self.client.session
        session['user_data'] = {'email': 'user1@test.com', 'given_name': 'User1'}
        session.save()
        
        initial_count = Messaging.objects.count()
        
        self.client.post(
            reverse('messaging:send-message', kwargs={'username': 'user2@test.com'}),
            {'content': '   '}  # Only whitespace
        )
        
        self.assertEqual(Messaging.objects.count(), initial_count)


class NotificationViewTests(TestCase):
    """Test the notifications view"""
    
    def setUp(self):
        self.client = Client()
        self.user1 = DjangoUser.objects.create_user(
            username='user1@test.com',
            email='user1@test.com',
            password='testpass123'
        )
        self.user2 = DjangoUser.objects.create_user(
            username='user2@test.com',
            email='user2@test.com',
            password='testpass123'
        )
        self.message = Messaging.objects.create(
            author=self.user1,
            recipient=self.user2,
            content="Test message"
        )
    
    def test_notifications_view_requires_login(self):
        """Test that notifications view redirects if not logged in"""
        response = self.client.get(reverse('messaging:notifications'))
        self.assertEqual(response.status_code, 302)
        self.assertIn('/login/', response.url)
    
    
    def test_mark_notification_as_read(self):
        """Test marking a notification as read"""
        notification = Notification.objects.create(
            recipient=self.user2,
            message=self.message
        )
        
        session = self.client.session
        session['user_data'] = {'email': 'user2@test.com', 'given_name': 'User2'}
        session.save()
        
        response = self.client.post(
            reverse('messaging:mark-read', kwargs={'notification_id': notification.id})
        )
        
        self.assertEqual(response.status_code, 302)
        notification.refresh_from_db()
        self.assertTrue(notification.is_read)
    
    def test_cannot_mark_others_notification_as_read(self):
        """Test that users can't mark other users' notifications as read"""
        notification = Notification.objects.create(
            recipient=self.user2,
            message=self.message
        )
        
        session = self.client.session
        session['user_data'] = {'email': 'user1@test.com', 'given_name': 'User1'}
        session.save()
        
        response = self.client.post(
            reverse('messaging:mark-read', kwargs={'notification_id': notification.id})
        )
        
        self.assertEqual(response.status_code, 404)


