class StartChatViewTests(TestCase):
    """Test the start chat functionality"""
    
    def setUp(self):
        self.client = Client()
        self.user1 = DjangoUser.objects.create_user(
            username='user1@test.com',
            email='user1@test.com',
            password='testpass123'
        )
        self.user2 = DjangoUser.objects.create_user(
            username='user2@test.com',
            email='user2@test.com',
            password='testpass123'
        )
        self.user3 = DjangoUser.objects.create_user(
            username='user3@test.com',
            email='user3@test.com',
            password='testpass123'
        )
    
    def test_start_chat_requires_login(self):
        """Test that start chat requires login"""
        response = self.client.get(reverse('messaging:start-chat'))
        self.assertEqual(response.status_code, 302)
        self.assertIn('/login/', response.url)
    
    def test_start_chat_displays_users(self):
        """Test that start chat displays available users"""
        session = self.client.session
        session['user_data'] = {'email': 'user1@test.com', 'given_name': 'User1'}
        session.save()
        
        response = self.client.get(reverse('messaging:start-chat'))
        self.assertEqual(response.status_code, 200)
        self.assertContains(response, 'user2@test.com')
        self.assertContains(response, 'user3@test.com')
        self.assertNotContains(response, 'user1@test.com')  # Current user shouldn't appear
    
    def test_start_individual_chat(self):
        """Test starting a chat with one user"""
        session = self.client.session
        session['user_data'] = {'email': 'user1@test.com', 'given_name': 'User1'}
        session.save()
        
        response = self.client.post(
            reverse('messaging:start-chat'),
            {'members': [self.user2.id]}
        )
        
        self.assertEqual(response.status_code, 302)
        self.assertIn(f'/messaging/chat/{self.user2.username}/', response.url)
    
    def test_start_group_chat(self):
        """Test starting a group chat with multiple users"""
        session = self.client.session
        session['user_data'] = {'email': 'user1@test.com', 'given_name': 'User1'}
        session.save()
        
        response = self.client.post(
            reverse('messaging:start-chat'),
            {'members': [self.user2.id, self.user3.id]}
        )
        
        self.assertEqual(response.status_code, 302)
        self.assertIn('/messaging/group/', response.url)
        
        # Verify group was created
        group = Group.objects.last()
        self.assertEqual(group.members.count(), 3)
        self.assertIn(self.user1, group.members.all())
        self.assertIn(self.user2, group.members.all())
        self.assertIn(self.user3, group.members.all())


